t.script:
//
var cur = 0;
var N   = 4;

function switchTab(tab) {
    document.getElementById('tab-reg').classList.toggle('active', tab === 'register');
    document.getElementById('tab-trk').classList.toggle('active', tab === 'status');
    document.getElementById('reg-card').style.display = (tab === 'register') ? '' : 'none';
    document.getElementById('trk-card').style.display = (tab === 'status')   ? '' : 'none';
}

function showS(n) {
    var secs = document.querySelectorAll('.ksa-sec');
    for (var i = 0; i < secs.length; i++) { secs[i].classList.remove('visible'); }
    document.getElementById('s' + n).classList.add('visible');

    for (var i = 0; i < N; i++) {
        var dot = document.getElementById('dot-' + i);
        var ps  = document.getElementById('ps-'  + i);
        var pl  = document.getElementById('pl-'  + i);
        dot.classList.remove('active', 'done');
        if (ps) { ps.classList.remove('active', 'done'); }
        if (i < n)  { dot.classList.add('done');   if (ps) ps.classList.add('done');   }
        if (i === n) { dot.classList.add('active'); if (ps) ps.classList.add('active'); }
        if (pl) { if (i < n) { pl.classList.add('done'); } else { pl.classList.remove('done'); } }
    }

    document.getElementById('btn-prev').style.display = (n > 0)       ? '' : 'none';
    document.getElementById('btn-next').style.display = (n < N - 1)   ? '' : 'none';
    document.getElementById('btn-sub').style.display  = (n === N - 1) ? '' : 'none';

    if (n === N - 1) { buildSum(); }
    cur = n;
}

function nextS() { if (validate(cur)) { showS(cur + 1); } }
function prevS() { if (cur > 0)       { showS(cur - 1); } }

function validate(n) {
    var ok = true;
    if (n === 0) {
        var ids = ['requester_name', 'requester_email', 'requester_company'];
        for (var i = 0; i < ids.length; i++) {
            var el = document.getElementById(ids[i]);
            if (!el.value.trim()) { el.classList.add('err'); ok = false; }
            else                  { el.classList.remove('err'); }
        }
        if (!ok) { toastMsg('Please fill required fields.', true); }
    }
    if (n === 2) {
        var el = document.getElementById('goods_description');
        if (!el.value.trim()) {
            el.classList.add('err');
            ok = false;
            toastMsg('Please describe your goods.', true);
        } else { el.classList.remove('err'); }
    }
    if (n === 3) {
        var agreeChk = document.getElementById('ksa-agree-chk');
        if (!agreeChk.checked) {
            document.getElementById('ksa-agree-row').style.outline = '2px solid #e53e3e';
            ok = false;
            toastMsg('Please read and agree to the Service Contract terms.', true);
        } else {
            document.getElementById('ksa-agree-row').style.outline = '';
        }
    }
    return ok;
}

function buildSum() {
    var ct = document.querySelector('input[name="clearance_type"]:checked');
    var rt = document.querySelector('input[name="request_type"]:checked');
    var rows = [
        ['Requester', gv('requester_name') + ' \u2014 ' + gv('requester_company')],
        ['Email',     gv('requester_email')],
        ['Type',      rt ? rt.value : '\u2014'],
        ['Clearance', ct ? ct.value : '\u2014'],
        ['Mode',      gv('shipment_type')],
        ['BL No.',    gv('bill_of_lading_no') || '\u2014'],
        ['ETA',       gv('eta') || '\u2014'],
        ['Value',     gv('estimated_value') ? (gv('estimated_value') + ' ' + gv('currency_note')) : '\u2014']
    ];
    var html = '';
    for (var i = 0; i < rows.length; i++) {
        var k = rows[i][0];
        var v = rows[i][1] || '\u2014';
        html += '<div class="sum-row"><span class="sum-key">' + k + '</span><span class="sum-val">' + v + '</span></div>';
    }
    document.getElementById('sum-content').innerHTML = html;
}

var DOC_IDS = ['has_bill_of_lading','has_invoice','has_packing_list','has_coo','has_saber_scoc','has_sfda','has_citc'];

function contractFileSelected(input) {
    var zone = document.getElementById('ksa-contract-zone');
    var fname = document.getElementById('ksa-contract-fname');
    var label = document.getElementById('ksa-contract-trigger-label');
    if (input.files && input.files[0]) {
        zone.classList.add('done');
        fname.textContent = input.files[0].name;
        label.innerHTML = '&#x2714; Signed Contract Selected <span class="ksa-optional-tag" style="background:#1a6b35;">Uploaded</span>';
    }
}

function submitF() {
    if (!validate(cur)) { return; }
    var btn = document.getElementById('btn-sub');
    btn.disabled = true;
    btn.textContent = 'Submitting...';

    var ct = document.querySelector('input[name="clearance_type"]:checked');
    var rt = document.querySelector('input[name="request_type"]:checked');

    var data = {
        request_type:             rt ? rt.value : 'supplier',
        requester_name:           gv('requester_name'),
        requester_email:          gv('requester_email'),
        requester_phone:          gv('requester_phone'),
        requester_company:        gv('requester_company'),
        requester_cr_no:          gv('requester_cr_no'),
        requester_vat_no:         gv('requester_vat_no'),
        requester_country_code:   gv('requester_country_code'),
        requester_city:           gv('requester_city'),
        clearance_type:           ct ? ct.value : 'import',
        shipment_type:            gv('shipment_type'),
        country_origin_code:      gv('country_origin_code'),
        country_destination_code: gv('country_destination_code'),
        port_of_loading:          gv('port_of_loading'),
        port_of_discharge:        gv('port_of_discharge'),
        vessel_name:              gv('vessel_name'),
        bill_of_lading_no:        gv('bill_of_lading_no'),
        eta:                      gv('eta'),
        gross_weight:             gv('gross_weight'),
        volume:                   gv('volume'),
        packages_count:           gv('packages_count'),
        goods_description:        gv('goods_description'),
        hs_codes_list:            gv('hs_codes_list'),
        estimated_value:          gv('estimated_value'),
        currency_note:            gv('currency_note'),
        has_bill_of_lading:       cb('has_bill_of_lading'),
        has_invoice:              cb('has_invoice'),
        has_packing_list:         cb('has_packing_list'),
        has_coo:                  cb('has_coo'),
        has_saber_scoc:           cb('has_saber_scoc'),
        has_sfda:                 cb('has_sfda'),
        has_citc:                 cb('has_citc'),
        additional_docs:          gv('additional_docs'),
        acd_reference_no:         gv('acd_reference_no'),
        saber_scoc_no:            gv('saber_scoc_no'),
        sfda_approval_no:         gv('sfda_approval_no'),
        fatoorah_invoice_no:      gv('fatoorah_invoice_no')
    };

    fetch('/customs-portal/submit', {
        method:  'POST',
        headers: { 'Content-Type': 'application/json', 'X-Requested-With': 'XMLHttpRequest' },
        body:    JSON.stringify({ jsonrpc: '2.0', method: 'call', params: data })
    })
    .then(function(resp) { return resp.json(); })
    .then(function(result) {
        if (result.success) {
            var token = result.token || '';
            /* Collect files selected for checked doc types */
            var uploads = [];
            for (var i = 0; i < DOC_IDS.length; i++) {
                var fi = document.getElementById('fi_' + DOC_IDS[i]);
                if (fi && fi.files && fi.files[0]) {
                    uploads.push({ docId: DOC_IDS[i], file: fi.files[0] });
                }
            }
            /* Collect signed contract file if provided */
            var contractFile = document.getElementById('ksa-contract-file');
            if (contractFile && contractFile.files && contractFile.files[0]) {
                uploads.push({ docId: 'contract_doc', file: contractFile.files[0] });
            }
            if (uploads.length === 0) { showSuccess(result); return; }
            btn.textContent = 'Uploading files...';
            var promises = [];
            for (var j = 0; j < uploads.length; j++) {
                var fd = new FormData();
                fd.append('token', token);
                fd.append('doc_field', uploads[j].docId);
                fd.append('file', uploads[j].file, uploads[j].file.name);
                promises.push(fetch('/customs-portal/upload-doc', { method: 'POST', body: fd }));
            }
            Promise.all(promises)
                .then(function() { showSuccess(result); })
                .catch(function() { showSuccess(result); });
        } else {
            toastMsg('Error: ' + (result.error || 'Submission failed'), true);
            btn.disabled = false;
            btn.textContent = 'Submit Request';
        }
    })
    .catch(function() {
        toastMsg('Connection error. Please try again.', true);
        btn.disabled = false;
        btn.textContent = 'Submit Request';
    });
}

function showSuccess(result) {
    document.getElementById('res-ref').textContent          = result.reference || '\u2014';
    document.getElementById('res-link').href                = '/customs-portal/status/' + (result.token || '');
    document.getElementById('ksa-form-body').style.display  = 'none';
    document.getElementById('ksa-success').style.display    = 'block';
}

function resetF() {
    document.getElementById('ksa-success').style.display   = 'none';
    document.getElementById('ksa-form-body').style.display = '';
    var inputs = document.querySelectorAll('#ksa-form-body input[type=text], #ksa-form-body input[type=email], #ksa-form-body input[type=tel], #ksa-form-body input[type=number], #ksa-form-body input[type=date], #ksa-form-body textarea');
    for (var i = 0; i < inputs.length; i++) { inputs[i].value = ''; }
    var checkboxes = document.querySelectorAll('#ksa-form-body input[type=checkbox]');
    for (var i = 0; i < checkboxes.length; i++) { checkboxes[i].checked = false; }
    /* Reset upload zones */
    for (var j = 0; j < DOC_IDS.length; j++) {
        var uz = document.getElementById('uz_' + DOC_IDS[j]);
        var fi = document.getElementById('fi_' + DOC_IDS[j]);
        var fn = document.getElementById('fn_' + DOC_IDS[j]);
        if (uz) { uz.style.display = 'none'; uz.classList.remove('done'); }
        if (fi) { fi.value = ''; }
        if (fn) { fn.textContent = ''; }
    }
    var labels = document.querySelectorAll('.ksa-doc-chk');
    for (var k = 0; k < labels.length; k++) { labels[k].classList.remove('active'); }
    /* Reset contract zone */
    var czone = document.getElementById('ksa-contract-zone');
    var cfile = document.getElementById('ksa-contract-file');
    var cfname = document.getElementById('ksa-contract-fname');
    var clabel = document.getElementById('ksa-contract-trigger-label');
    if (czone) { czone.classList.remove('done'); }
    if (cfile) { cfile.value = ''; }
    if (cfname) { cfname.textContent = ''; }
    if (clabel) { clabel.innerHTML = 'Upload Signed Contract <span class="ksa-optional-tag">Optional</span>'; }
    var agreeRow = document.getElementById('ksa-agree-row');
    if (agreeRow) { agreeRow.style.outline = ''; }
    showS(0);
}

function checkStatus() {
    var token = document.getElementById('track-token').value.trim();
    if (!token) { toastMsg('Please enter a reference number.', true); return; }
    var res   = document.getElementById('ksa-sresult');
    var badge = document.getElementById('sbadge-wrap');
    var det   = document.getElementById('sdetails');
    res.style.display   = 'block';
    badge.innerHTML     = '<div style="color:var(--muted);font-size:13px;padding:10px 0;">Checking&#x2026;</div>';
    det.innerHTML       = '';
    setTimeout(function() {
        window.location.href = '/customs-portal/status/' + encodeURIComponent(token);
    }, 400);
}

function gv(id) { var el = document.getElementById(id); return el ? el.value : ''; }
function cb(id) { var el = document.getElementById(id); return el ? el.checked : false; }

function toastMsg(msg, isErr) {
    var el = document.getElementById('ksa-toast');
    el.textContent = msg;
    el.className   = 'ksa-toast show' + (isErr ? ' err' : '');
    setTimeout(function() { el.classList.remove('show'); }, 3200);
}

function toggleDoc(checkbox) {
    var docId = checkbox.id;
    var label = checkbox.closest('.ksa-doc-chk') || checkbox.parentElement;
    var uz    = document.getElementById('uz_' + docId);
    if (checkbox.checked) {
        label.classList.add('active');
        if (uz) { uz.style.display = ''; }
    } else {
        label.classList.remove('active');
        if (uz) {
            uz.style.display = 'none';
            uz.classList.remove('done');
            var fi = document.getElementById('fi_' + docId);
            var fn = document.getElementById('fn_' + docId);
            if (fi) { fi.value = ''; }
            if (fn) { fn.textContent = ''; }
        }
    }
}

function fileSelected(input, docId) {
    var uz = document.getElementById('uz_' + docId);
    var fn = document.getElementById('fn_' + docId);
    if (input.files && input.files[0]) {
        uz.classList.add('done');
        fn.textContent = input.files[0].name;
    } else {
        uz.classList.remove('done');
        fn.textContent = '';
    }
}
showS(0);
//

//
var TRK_TOKEN = '';
(function() {
    var el = document.getElementById('trk-token-holder');
    if (el) { TRK_TOKEN = el.getAttribute('data-token') || ''; }
})();

function trkToggle(checkbox, docId) {
    var uz   = document.getElementById('trkuz_'   + docId);
    var lbl  = document.getElementById('trklbl_'  + docId);
    if (checkbox.checked) {
        if (uz)  { uz.style.display = ''; }
        if (lbl) { lbl.className = 'trk-doc-upload-toggle done'; }
    } else {
        if (uz)  { uz.style.display = 'none'; }
        if (lbl) { lbl.className = 'trk-doc-upload-toggle'; }
        var fi   = document.getElementById('trkfi_'   + docId);
        var fn   = document.getElementById('trkfn_'   + docId);
        var prog = document.getElementById('trkprog_' + docId);
        var err  = document.getElementById('trkerr_'  + docId);
        var zone = document.getElementById('trkzone_' + docId);
        if (fi)   { fi.value = ''; }
        if (fn)   { fn.style.display = 'none'; fn.textContent = ''; }
        if (prog) { prog.style.display = 'none'; }
        if (err)  { err.style.display = 'none'; err.textContent = ''; }
        if (zone) { zone.className = 'trk-doc-upload-label'; }
    }
}

function trkUpload(input, docId) {
    if (!input.files || !input.files[0]) { return; }
    var file = input.files[0];
    var prog = document.getElementById('trkprog_' + docId);
    var fn   = document.getElementById('trkfn_'   + docId);
    var err  = document.getElementById('trkerr_'  + docId);
    var zone = document.getElementById('trkzone_' + docId);
    var ico  = document.getElementById('trkico_'  + docId);
    var tag  = document.getElementById('trktag_'  + docId);
    var lbl  = document.getElementById('trklbl_'  + docId);

    if (fn)   { fn.style.display = 'none'; }
    if (err)  { err.style.display = 'none'; }
    if (prog) { prog.style.display = ''; }
    if (zone) { zone.className = 'trk-doc-upload-label'; }

    var fd = new FormData();
    fd.append('token',     TRK_TOKEN);
    fd.append('doc_field', docId);
    fd.append('file',      file, file.name);

    fetch('/customs-portal/upload-doc', { method: 'POST', body: fd })
    .then(function(r) { return r.json(); })
    .then(function(resp) {
        if (prog) { prog.style.display = 'none'; }
        if (resp.success) {
            /* show file name */
            if (fn) { fn.textContent = '✓ ' + file.name; fn.style.display = ''; }
            /* green upload zone */
            if (zone) { zone.className = 'trk-doc-upload-label success'; }
            /* update row icon + tag */
            if (ico) { ico.className = 'trk-doc-ico ok'; ico.textContent = '✓'; }
            if (tag) { tag.className = 'trk-doc-tag ok'; tag.textContent = 'Uploaded'; }
            if (lbl) { lbl.className = 'trk-doc-upload-toggle done'; }
            /* add to uploaded files list */
            trkAddFile(file.name, resp.attachment_id || 0);
        } else {
            if (err) {
                err.textContent = 'Upload failed: ' + (resp.error || 'Unknown error');
                err.style.display = '';
            }
        }
    })
    .catch(function() {
        if (prog) { prog.style.display = 'none'; }
        if (err) { err.textContent = 'Connection error. Please try again.'; err.style.display = ''; }
    });
}

function trkAddFile(name, attId) {
    var list  = document.getElementById('trk-uploaded-list');
    var empty = document.getElementById('trk-uploaded-empty');
    if (!list) { return; }
    if (empty) { empty.style.display = 'none'; }
    var row  = document.createElement('div');
    row.className = 'trk-doc-item';
    var ico  = document.createElement('div');
    ico.className = 'trk-doc-ico ok';
    ico.textContent = '📎';
    var nm   = document.createElement('span');
    nm.className = 'trk-doc-name';
    nm.textContent = name;
    var tag  = document.createElement('span');
    tag.className = 'trk-doc-tag ok';
    tag.textContent = '✓ Uploaded';
    row.appendChild(ico);
    row.appendChild(nm);
    row.appendChild(tag);
    list.appendChild(row);
}
//
